import{c as s,cG as i,cb as a,c8 as n,cf as t,cT as l,ce as p}from"./chunks/framework.BlkIsu1j.js";const e=JSON.parse('{"title":"21. 异常与中断","description":"","frontmatter":{"title":"21. 异常与中断","outline":"deep","layout":"doc","prev":{"text":"20. 特权级别与 CSR","link":"/lang/assembly/20_privilege_csr"},"next":{"text":"22. 页表与虚拟内存","link":"/lang/assembly/22_virtual_memory"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/21_exceptions_interrupts.md","filePath":"lang/assembly/21_exceptions_interrupts.md","lastUpdated":1780203085000}'),h={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"lang/assembly/21_exceptions_interrupts.md"},[["render",function(s,e,k,d,r,c){return i(),a("div",null,[n("h1",h,[t(l(s.$frontmatter.title)+" ",1),e[0]||(e[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),e[1]||(e[1]=p('<p>上一章介绍了 CSR 和三种特权模式。有了这些基础设施，我们现在可以深入理解 CPU 在遇到&quot;意外情况&quot;时的完整响应机制。RISC-V 将一切打断正常指令流的事件统一称作<strong>陷阱（Trap）</strong>——不论是非法指令、定时器到期、还是网卡数据到达，都走同一条硬件处理路径。这种统一设计大幅简化了硬件和控制软件（OS/固件）的结构。</p><h2 id="异常-vs-中断-vs-陷阱" tabindex="-1">异常 vs 中断 vs 陷阱 <a class="header-anchor" href="#异常-vs-中断-vs-陷阱" aria-label="Permalink to “异常 vs 中断 vs 陷阱”">​</a></h2><h3 id="三个术语的精确定义" tabindex="-1">三个术语的精确定义 <a class="header-anchor" href="#三个术语的精确定义" aria-label="Permalink to “三个术语的精确定义”">​</a></h3><p>在 RISC-V 规范中，这三个词有严格区分：</p><table tabindex="0"><thead><tr><th>术语</th><th>英文</th><th>本质</th><th>举例</th></tr></thead><tbody><tr><td>异常</td><td>Exception</td><td><strong>同步</strong>事件——由当前指令的执行直接触发</td><td>非法指令、ecall、断点、页错误、地址不对齐</td></tr><tr><td>中断</td><td>Interrupt</td><td><strong>异步</strong>事件——由外部设备/定时器触发，与当前指令无关</td><td>定时器到期、UART 接收数据、DMA 完成</td></tr><tr><td>陷阱</td><td>Trap</td><td>统称——异常和中断的总和</td><td>一切打断正常执行流的硬件事件</td></tr></tbody></table><p>关键区别在于<strong>时序的可预测性</strong>：</p><ul><li>异常与特定指令绑定——每次执行那条非法指令，异常一定发生</li><li>中断随时可能到达——硬件在当前指令执行完后、下一条指令执行前采样中断信号</li></ul><h3 id="为什么统一处理" tabindex="-1">为什么统一处理 <a class="header-anchor" href="#为什么统一处理" aria-label="Permalink to “为什么统一处理”">​</a></h3><p>RISC-V 有意将异常和中断统一为陷阱处理框架。好处：</p><ol><li><strong>一套硬件保存/恢复机制</strong>：<code>mepc</code>/<code>mcause</code>/<code>mtval</code> 对异常和中断同样适用</li><li><strong>统一的入口和出口</strong>：都通过 <code>mtvec</code> 进入处理程序，通过 <code>mret</code>/<code>sret</code> 返回</li><li><strong>统一的分发逻辑</strong>：处理程序读 <code>mcause</code> 的最高位判断是中断还是异常，然后走对应分支</li></ol><p>唯一的区别在于 <code>mepc</code> 的含义：对于异常，<code>mepc</code> 指向触发异常的指令（返回时需要重新执行或跳过）；对于中断，<code>mepc</code> 指向尚未执行的下一条指令（返回时继续执行）。</p><h2 id="陷阱相关-csr-总览" tabindex="-1">陷阱相关 CSR 总览 <a class="header-anchor" href="#陷阱相关-csr-总览" aria-label="Permalink to “陷阱相关 CSR 总览”">​</a></h2><p>第 20 章已经介绍了这些 CSR 的地址和基本用途，这里深入它们的陷阱相关语义。</p><h3 id="mtvec-陷阱向量的两种模式" tabindex="-1">mtvec：陷阱向量的两种模式 <a class="header-anchor" href="#mtvec-陷阱向量的两种模式" aria-label="Permalink to “mtvec：陷阱向量的两种模式”">​</a></h3><p><code>mtvec</code>（Machine Trap Vector）决定了陷阱发生后 PC 跳转到哪里：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mtvec[1:0] = 00 → Direct 模式</span></span>\n<span class="line"><span>               PC ← BASE (mtvec 的高位部分，4 字节对齐)</span></span>\n<span class="line"><span>mtvec[1:0] = 01 → Vectored 模式</span></span>\n<span class="line"><span>               PC ← BASE + 4 × cause_number (仅对中断有效)</span></span></code></pre></div><p><strong>Direct 模式</strong>（最常用）：所有陷阱都跳转到同一地址。处理程序通过 <code>mcause</code> 来区分处理。</p><p><strong>Vectored 模式</strong>：硬件根据中断编号自动计算跳转偏移。异常仍跳转到 BASE。此模式仅在中断向量表场景下有意义，可以减少处理程序的查表开销——但要求所有向量入口在 4 字节内放不下时使用无条件跳转指令扩展。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设置 Direct 模式陷阱向量</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, trap_handler</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mtvec, t0           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # bit[1:0] = 00（地址 4 字节对齐）</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设置 Vectored 模式陷阱向量</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, vector_table</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ori     t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # bit[0] = 1 使能 Vectored 模式</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mtvec, t0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vectored 模式下的中断向量表</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .align </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # 256 字节对齐（最多 64 个向量）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vector_table:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j     default_handler       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # cause 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j     ssi_handler           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # cause 1: Supervisor 软件中断</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j     default_handler       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # cause 2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j     msi_handler           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # cause 3: Machine 软件中断</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 等等</span></span></code></pre></div><h3 id="mepc-异常程序计数器" tabindex="-1">mepc：异常程序计数器 <a class="header-anchor" href="#mepc-异常程序计数器" aria-label="Permalink to “mepc：异常程序计数器”">​</a></h3><p>当陷阱发生时，硬件将当前 PC（或下一条指令的 PC）保存到 <code>mepc</code>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 陷阱处理程序读取故障地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, mepc            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 触发异常的指令地址</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 对于 ecall 指令，mepc 指向 ecall 本身</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 返回时：mepc+4 跳过 ecall，执行下一条指令</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi    t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mepc, t0            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 返回后继续执行下一条指令</span></span></code></pre></div><p>处理程序可以根据需要修改 <code>mepc</code>，以此来改变返回位置。这对于系统调用（ecall 返回后应执行下一条指令）、断点调试（单步执行）等场景至关重要。</p><h3 id="mcause-原因编码" tabindex="-1">mcause：原因编码 <a class="header-anchor" href="#mcause-原因编码" aria-label="Permalink to “mcause：原因编码”">​</a></h3><p><code>mcause</code> 是陷阱处理程序的核心分发依据。它的位布局：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mcause[XLEN-1]    = Interrupt 位：1 = 中断，0 = 异常</span></span>\n<span class="line"><span>mcause[XLEN-2:0]   = 异常/中断编号</span></span></code></pre></div><p>完整的编码表：</p><p><strong>异常编码（mcause[XLEN-1]=0）：</strong></p><table tabindex="0"><thead><tr><th>编号</th><th>名称</th><th>触发场景</th></tr></thead><tbody><tr><td>0</td><td>Instruction address misaligned</td><td>跳转目标地址未对齐</td></tr><tr><td>1</td><td>Instruction access fault</td><td>取指时发生物理内存访问错误</td></tr><tr><td>2</td><td>Illegal instruction</td><td>操作码在实现的 ISA 中不存在</td></tr><tr><td>3</td><td>Breakpoint</td><td><code>ebreak</code> 指令或调试断点</td></tr><tr><td>4</td><td>Load address misaligned</td><td>load 地址不对齐（非对齐访问未使能时）</td></tr><tr><td>5</td><td>Load access fault</td><td>load 操作发生物理内存访问错误</td></tr><tr><td>6</td><td>Store/AMO address misaligned</td><td>store/AMO 地址不对齐</td></tr><tr><td>7</td><td>Store/AMO access fault</td><td>store/AMO 发生物理内存访问错误</td></tr><tr><td>8</td><td>Environment call from U-mode</td><td>用户态 <code>ecall</code></td></tr><tr><td>9</td><td>Environment call from S-mode</td><td>内核态 <code>ecall</code>（S 模式调用 M 模式固件）</td></tr><tr><td>11</td><td>Environment call from M-mode</td><td>M 模式 <code>ecall</code>（较少使用）</td></tr><tr><td>12</td><td>Instruction page fault</td><td>取指时页表翻译失败（虚拟内存系统）</td></tr><tr><td>13</td><td>Load page fault</td><td>Load 时页表翻译失败</td></tr><tr><td>15</td><td>Store/AMO page fault</td><td>Store/AMO 时页表翻译失败</td></tr></tbody></table><p><strong>中断编码（mcause[XLEN-1]=1）：</strong></p><table tabindex="0"><thead><tr><th>编号</th><th>名称</th><th>触发场景</th></tr></thead><tbody><tr><td>1</td><td>Supervisor software interrupt</td><td>S 模式间 hart 间中断（IPI）</td></tr><tr><td>3</td><td>Machine software interrupt</td><td>M 模式间 hart 间中断</td></tr><tr><td>5</td><td>Supervisor timer interrupt</td><td>S 模式定时器中断</td></tr><tr><td>7</td><td>Machine timer interrupt</td><td>M 模式定时器中断</td></tr><tr><td>9</td><td>Supervisor external interrupt</td><td>S 模式外部中断（PLIC 分发）</td></tr><tr><td>11</td><td>Machine external interrupt</td><td>M 模式外部中断</td></tr></tbody></table><p>值得注意的是，编号 10/14 等跳过的编码保留给将来使用——RISC-V 设计者的远见。</p><h3 id="mtval-附加信息" tabindex="-1">mtval：附加信息 <a class="header-anchor" href="#mtval-附加信息" aria-label="Permalink to “mtval：附加信息”">​</a></h3><p><code>mtval</code> 的内容取决于陷阱类型：</p><ul><li>非法指令（cause=2）：<code>mtval</code> 包含非法指令的编码本身</li><li>地址不对齐（cause=0/4/6）：<code>mtval</code> 包含问题地址</li><li>页错误（cause=12/13/15）：<code>mtval</code> 包含引发错误的虚拟地址</li><li>断点（cause=3）：<code>mtval</code> 的值是实现定义的（implementation-defined）</li></ul><p>这个寄存器是可选的——在某些轻量级实现中 <code>mtval</code> 始终为 0。但对于调试和 OS 开发，<code>mtval</code> 提供的附加信息在定位问题时价值极大。</p><h3 id="mstatus-陷阱上下文保存与恢复" tabindex="-1">mstatus：陷阱上下文保存与恢复 <a class="header-anchor" href="#mstatus-陷阱上下文保存与恢复" aria-label="Permalink to “mstatus：陷阱上下文保存与恢复”">​</a></h3><p>陷阱发生时，<code>mstatus</code> 的关键字段自动执行以下操作：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>陷阱进入时（硬件自动）：</span></span>\n<span class="line"><span>  mstatus.MPIE ← mstatus.MIE    # 保存旧的中断使能</span></span>\n<span class="line"><span>  mstatus.MIE  ← 0              # 关全局中断</span></span>\n<span class="line"><span>  mstatus.MPP  ← 当前特权级     # 保存旧的特权级别</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>mret 执行时（硬件自动）：</span></span>\n<span class="line"><span>  mstatus.MIE  ← mstatus.MPIE   # 恢复旧的中断使能</span></span>\n<span class="line"><span>  mstatus.MPIE ← 1              # 重置 MPIE（为下次陷阱准备）</span></span>\n<span class="line"><span>  mstatus.MPP  ← 0 (U 模式)     # 重置 MPP</span></span>\n<span class="line"><span>  PC           ← mepc            # 跳回原位置</span></span></code></pre></div><p>这个自动保存-恢复协议的设计目的是：</p><ol><li><strong>避免嵌套陷阱</strong>：进入陷阱后立即关中断（MIE=0），防止处理程序处理到一半又被中断打断</li><li><strong>允许手动开中断</strong>：处理程序可以在保存上下文后重新开中断（将 MIE 置 1），支持中断嵌套</li><li><strong>MPP 记录来源</strong>：<code>mret</code> 通过 MPP 知道要返回到哪个特权级——这是跨特权级返回的必要信息</li></ol><h2 id="陷阱处理完整流程-6-步" tabindex="-1">陷阱处理完整流程（6 步） <a class="header-anchor" href="#陷阱处理完整流程-6-步" aria-label="Permalink to “陷阱处理完整流程（6 步）”">​</a></h2><p>以一个完整的 M 模式陷阱处理为例，展示从头到尾的 6 步流程：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第 1 步：硬件自动保存</span></span>\n<span class="line"><span>  mepc    ← PC（异常）或 PC+4（中断）</span></span>\n<span class="line"><span>  mcause  ← 原因编码</span></span>\n<span class="line"><span>  mtval   ← 附加信息（如有）</span></span>\n<span class="line"><span>  mstatus.MPP  ← 当前特权级</span></span>\n<span class="line"><span>  mstatus.MPIE ← mstatus.MIE</span></span>\n<span class="line"><span>  mstatus.MIE  ← 0</span></span>\n<span class="line"><span>  PC      ← mtvec（跳转到处理程序）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 2 步：软件保存上下文</span></span>\n<span class="line"><span>  将所有可能被破坏的通用寄存器压入栈或暂存区</span></span>\n<span class="line"><span>  这是 trap_handler 的前几行代码</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 3 步：读取 mcause 并分发</span></span>\n<span class="line"><span>  根据最高位判断中断 vs 异常</span></span>\n<span class="line"><span>  根据低 12 位编号跳转到对应的处理逻辑</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 4 步：执行具体处理</span></span>\n<span class="line"><span>  异常处理：打印错误、kill 进程、修复页表等</span></span>\n<span class="line"><span>  中断处理：更新 mtimecmp、读取外设数据等</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 5 步：恢复上下文</span></span>\n<span class="line"><span>  从栈或暂存区恢复所有通用寄存器</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 6 步：mret 返回</span></span>\n<span class="line"><span>  PC      ← mepc</span></span>\n<span class="line"><span>  特权级  ← mstatus.MPP</span></span>\n<span class="line"><span>  MIE     ← mstatus.MPIE</span></span>\n<span class="line"><span>  继续执行被打断的代码</span></span></code></pre></div><p>对应的汇编框架：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .align </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trap_handler:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ---- 第 2 步：保存上下文 ----</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi    </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 在栈上分配 32×8 字节空间</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      ra, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保存返回地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保存临时寄存器</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 保存 t3-t6, a0-a7, s0-s11, gp, tp ...</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ---- 第 3 步：读 mcause 并分发 ----</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, mcause</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bge     t0, x0, is_exception</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 最高位为 0 → 异常</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 最高位为 1 → 中断</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">is_interrupt:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    andi    t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 提取中断编号</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # Machine timer interrupt = 7</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beq     t1, t2, handle_mti</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # Machine software interrupt = 3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beq     t1, t2, handle_msi</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">11</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # Machine external interrupt = 11</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beq     t1, t2, handle_mei</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j       trap_exit           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 未知中断，直接返回</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">is_exception:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    andi    t1, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0xFFF</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 提取异常编号</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # Illegal instruction</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beq     t1, t2, handle_illegal</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # ecall from U-mode</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beq     t1, t2, handle_ecall</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 其他异常处理 ...</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ---- 第 4 步后段 + 第 5 步 + 第 6 步 ----</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">trap_exit:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 恢复上下文</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      ra, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 恢复所有寄存器 ...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi    </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 回收栈空间</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mret                        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 返回被打断的代码</span></span></code></pre></div><h2 id="定时器中断详解" tabindex="-1">定时器中断详解 <a class="header-anchor" href="#定时器中断详解" aria-label="Permalink to “定时器中断详解”">​</a></h2><p>定时器中断是操作系统实现抢占式调度的基石——没有它，一个死循环就能霸占整个 CPU。</p><h3 id="mtime-与-mtimecmp" tabindex="-1">mtime 与 mtimecmp <a class="header-anchor" href="#mtime-与-mtimecmp" aria-label="Permalink to “mtime 与 mtimecmp”">​</a></h3><p>定时器机制由两个 MMIO 寄存器组成（注意：不是 CSR，是通过内存地址访问的）：</p><table tabindex="0"><thead><tr><th>寄存器</th><th>访问方式</th><th>描述</th></tr></thead><tbody><tr><td><code>mtime</code></td><td>MMIO（平台定义地址）</td><td>单调递增的 64 位计数器，由恒定频率时钟驱动</td></tr><tr><td><code>mtimecmp</code></td><td>MMIO（平台定义地址）</td><td>64 位比较值；当 <code>mtime &gt;= mtimecmp</code> 时触发定时器中断</td></tr></tbody></table><p>QEMU virt 平台的典型地址：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mtime:     0x0200BFF8（RV64）</span></span>\n<span class="line"><span>mtimecmp:  0x02004000 + 8 × hart_id（每个 hart 独立）</span></span></code></pre></div><p>时钟频率通常为 10 MHz（QEMU 默认）——这意味着 <code>mtime</code> 每 100ns 加 1。</p><h3 id="定时器中断处理流程" tabindex="-1">定时器中断处理流程 <a class="header-anchor" href="#定时器中断处理流程" aria-label="Permalink to “定时器中断处理流程”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 设置首次定时器中断 ----</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setup_timer:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x200BFF8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # mtime 的 MMIO 地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 当前 mtime 值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10000000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 10M 个 tick ≈ 1 秒（10 MHz 时钟）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t1, t1, t2          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 下次触发时间</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x2004000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # mtimecmp 的 MMIO 地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 写 mtimecmp</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 使能 M 模式定时器中断</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MTIE = bit 7</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    mie, t0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 开定时器中断使能</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    mstatus, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 开 M 模式全局中断</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 定时器中断处理程序 ----</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">handle_mti:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # （上下文已在 trap_handler 中保存）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 1. 确认：读 mip 检查 MTIP 位</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrr    t0, mip</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    andi    t0, t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MTIP = bit 7</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    beqz    t0, trap_exit       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 不是定时器中断，跳过</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 2. 设置下次中断</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x200BFF8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # mtime 地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t1 = 当前 mtime</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t2, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10000000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 1 秒后再次触发</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t1, t1, t2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x2004000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # mtimecmp 地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 3. 执行定时器相关逻辑（如进程调度）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    #    call schedule 或简单的计数器递增</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, tick_count</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    addi    t1, t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sd      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(t0)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 4. 跳转到共享退出路径（恢复上下文 + mret）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j       trap_exit</span></span></code></pre></div><p>三个容易出错的地方：</p><ol><li><strong>mtimecmp 必须在处理程序中更新</strong>：如果不在处理程序中写 mtimecmp，中断将持续触发（mtime 只增不减，中断条件一直成立）</li><li><strong>mmio 读取 mtime 是易失的</strong>：必须每次都从 MMIO 地址加载，不能将之前的值缓存在寄存器中假设它不变</li><li><strong>MIE 的位精确性</strong>：<code>mie.MTIE</code>(bit 7) 和 <code>mip.MTIP</code>(bit 7) 是定时器中断的配对使能和挂起位——两处都要正确操作</li></ol><h3 id="完整-bare-metal-定时器示例" tabindex="-1">完整 bare-metal 定时器示例 <a class="header-anchor" href="#完整-bare-metal-定时器示例" aria-label="Permalink to “完整 bare-metal 定时器示例”">​</a></h3><p>以下是一个完整的 bare-metal 中断驱动 tick 计数器：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .data</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tick_count:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dword</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .text</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .globl _start</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">_start:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, _stack_top</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, trap_handler</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    mtvec, t0           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 设置 Direct 模式陷阱向量</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    setup_timer         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 初始化定时器</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    mstatus, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 全局开中断</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">main_loop:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    wfi                         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 等待中断（WFI = Wait For Interrupt）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 中断返回后，继续 wfi</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    j       main_loop</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># trap_handler 和 handle_mti 的定义如上所示</span></span></code></pre></div><p>程序的控制流是：<code>wfi</code> → 定时器中断 → <code>trap_handler</code> → <code>handle_mti</code> → <code>mret</code> → 回到 <code>wfi</code> → 再次等待。这是一个最小但完整的定时器驱动系统。</p><h2 id="异常委托与中断委托" tabindex="-1">异常委托与中断委托 <a class="header-anchor" href="#异常委托与中断委托" aria-label="Permalink to “异常委托与中断委托”">​</a></h2><p>在支持 S 模式的系统中，M 模式固件可以将某些陷阱&quot;下放&quot;给 S 模式：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 将 U 模式 ecall（异常 8）委托给 S 模式</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    medeleg, t0         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 委托的异常不再在 M 模式处理</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 将 S 模式定时器中断（中断 5）委托给 S 模式</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrs    mideleg, t0         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 委托的中断不再在 M 模式处理</span></span></code></pre></div><p>委托之后，这些陷阱会直接使用 <code>sepc</code>/<code>scause</code>/<code>stval</code>/<code>stvec</code> 等 S 模式 CSR，而不再经过 <code>mepc</code>/<code>mcause</code> 等 M 模式 CSR。这是 Linux 内核启动流程中的关键步骤——OpenSBI 固件将定时器、外部中断等委托给 Linux 内核，自身只保留对不可恢复错误的处理。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>陷阱（Trap）是异常（同步）和中断（异步）的统一抽象——都被 <code>mtvec</code> → CSR 保存 → 分发 → <code>mret</code> 这一条管道处理</li><li><code>mtvec</code> 控制陷阱去向（Direct 单入口 / Vectored 按编号偏移），<code>mcause</code> 的最高位区分中断/异常，低 12 位提供精确的原因编号</li><li>陷阱处理的 6 步流程：硬件自动保存 CSR → 软件压栈寄存器 → 读 mcause 分发 → 执行处理逻辑 → 出栈恢复 → mret 返回</li><li>定时器中断依赖 MMIO 寄存器 mtime/mtimecmp（非 CSR）——处理程序中必须写 mtimecmp 为新值来&quot;应答&quot;中断，否则中断将持续触发</li><li>委托机制（<code>medeleg</code>/<code>mideleg</code>）让 M 模式固件将大部分陷阱下放给 S 模式 OS，自己仅处理最底层不可恢复事件</li></ul>',68))])}]]);export{e as __pageData,k as default};
